//! Exercise the V2 / V3 decoders against real production mainnet calldata.
//!
//! Test corpus captured 2026-05-15 from `ethereum-rpc.publicnode.com` by
//! scanning recent blocks for txes to:
//!  - 0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D (Uniswap V2 router)
//!  - 0xE592427A0AEce92De3Edee1F18E0157C05861564 (Uniswap V3 SwapRouter)
//!
//! The point is to verify whether `abi_decode(.., validate=true)` accepts
//! ABI-valid calldata that wasn't produced by alloy's own encoder. Synthetic
//! `*Call::abi_encode()` round-trips trivially pass strict validation; only
//! third-party encodings (wallets, dApp SDKs) can surface canonical-encoding
//! divergences in practice.

use std::str::FromStr as _;

use abi_resolver::decoder::{DecodeContext, Decoder};
use abi_resolver::decoders::uniswap_v2::{
    SwapETHForExactTokensDecoder, SwapExactETHForTokensDecoder, SwapExactTokensForETHDecoder,
    SwapExactTokensForTokensDecoder, SwapTokensForExactETHDecoder,
    SwapTokensForExactTokensDecoder,
};
use abi_resolver::decoders::uniswap_v3::{
    ExactInputDecoder, ExactInputSingleDecoder, ExactOutputDecoder, ExactOutputSingleDecoder,
};
use policy_engine::action::{Address, DecimalString};

const V2_ROUTER: &str = "0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D";
const V3_ROUTER: &str = "0xE592427A0AEce92De3Edee1F18E0157C05861564";

// V2: swapExactETHForTokens(amountOutMin, path, to, deadline)
const V2_SWAP_EXACT_ETH_FOR_TOKENS: &[&str] = &[
    "",
    "",
    "",
];

// V3 SwapRouter: exactOutputSingle((tokenIn, tokenOut, fee, recipient, deadline, amountOut, amountInMaximum, sqrtPriceLimitX96))
const V3_EXACT_OUTPUT_SINGLE: &[&str] = &[
    "",
];

// V3 SwapRouter: exactInputSingle((tokenIn, tokenOut, fee, recipient, deadline, amountIn, amountOutMinimum, sqrtPriceLimitX96))
const V3_EXACT_INPUT_SINGLE: &[&str] = &[
    "",
    "",
];

// V2: swapExactTokensForTokens(amountIn, amountOutMin, path, to, deadline)
const V2_SWAP_EXACT_TOKENS_FOR_TOKENS: &[&str] = &[
    "",
    "",
];

// V2: swapTokensForExactTokens(amountOut, amountInMax, path, to, deadline)
const V2_SWAP_TOKENS_FOR_EXACT_TOKENS: &[&str] = &[
    "",
    "",
];

// V2: swapTokensForExactETH(amountOut, amountInMax, path, to, deadline)
const V2_SWAP_TOKENS_FOR_EXACT_ETH: &[&str] = &[
    "",
    "",
];

// V2: swapExactTokensForETH(amountIn, amountOutMin, path, to, deadline)
const V2_SWAP_EXACT_TOKENS_FOR_ETH: &[&str] = &[
    "",
    "",
];

// V2: swapETHForExactTokens(amountOut, path, to, deadline)
const V2_SWAP_ETH_FOR_EXACT_TOKENS: &[&str] = &[
    "",
    "",
];

// V3 SwapRouter: exactInput((bytes path, recipient, deadline, amountIn, amountOutMinimum))
// path is dynamic-length bytes — most likely to surface validate=true ambiguities.
const V3_EXACT_INPUT: &[&str] = &[
    "",
    "",
];

// V3 SwapRouter: exactOutput((bytes path, recipient, deadline, amountOut, amountInMaximum))
// Same dynamic-path concern as exactInput. Second blob is a multi-hop path.
const V3_EXACT_OUTPUT: &[&str] = &[
    "",
    "",
];

fn build_ctx<'a>(to: &'a Address, value: &'a DecimalString) -> DecodeContext<'a> {
    DecodeContext {
        chain_id: 1,
        to,
        value,
        block_timestamp: Some(1_700_000_000),
    }
}

fn assert_decodes<D: Decoder>(label: &str, decoder: D, router: &str, blobs: &[&str]) {
    let to = Address::from_str(router).unwrap();
    let value = DecimalString::from_str("0").unwrap();
    let ctx = build_ctx(&to, &value);
    for (idx, blob) in blobs.iter().enumerate() {
        let calldata = hex::decode(blob).expect("hex");
        let result = decoder.decode(&ctx, &calldata);
        if let Err(err) = result {
            panic!(
                "{label} sample[{idx}] failed validate=true decode: {err}\n\
                 first 64 bytes of calldata: 0x{}",
                hex::encode(&calldata[..calldata.len().min(64)])
            );
        }
    }
}

#[test]
fn v2_swap_exact_eth_for_tokens_real_calldata_decodes() {
    assert_decodes(
        "V2.swapExactETHForTokens",
        SwapExactETHForTokensDecoder::new(),
        V2_ROUTER,
        V2_SWAP_EXACT_ETH_FOR_TOKENS,
    );
}

#[test]
fn v3_exact_output_single_real_calldata_decodes() {
    assert_decodes(
        "V3.exactOutputSingle",
        ExactOutputSingleDecoder::new(),
        V3_ROUTER,
        V3_EXACT_OUTPUT_SINGLE,
    );
}

#[test]
fn v3_exact_input_single_real_calldata_decodes() {
    assert_decodes(
        "V3.exactInputSingle",
        ExactInputSingleDecoder::new(),
        V3_ROUTER,
        V3_EXACT_INPUT_SINGLE,
    );
}

#[test]
fn v2_swap_exact_tokens_for_tokens_real_calldata_decodes() {
    assert_decodes(
        "V2.swapExactTokensForTokens",
        SwapExactTokensForTokensDecoder::new(),
        V2_ROUTER,
        V2_SWAP_EXACT_TOKENS_FOR_TOKENS,
    );
}

#[test]
fn v2_swap_tokens_for_exact_tokens_real_calldata_decodes() {
    assert_decodes(
        "V2.swapTokensForExactTokens",
        SwapTokensForExactTokensDecoder::new(),
        V2_ROUTER,
        V2_SWAP_TOKENS_FOR_EXACT_TOKENS,
    );
}

#[test]
fn v2_swap_tokens_for_exact_eth_real_calldata_decodes() {
    assert_decodes(
        "V2.swapTokensForExactETH",
        SwapTokensForExactETHDecoder::new(),
        V2_ROUTER,
        V2_SWAP_TOKENS_FOR_EXACT_ETH,
    );
}

#[test]
fn v2_swap_exact_tokens_for_eth_real_calldata_decodes() {
    assert_decodes(
        "V2.swapExactTokensForETH",
        SwapExactTokensForETHDecoder::new(),
        V2_ROUTER,
        V2_SWAP_EXACT_TOKENS_FOR_ETH,
    );
}

#[test]
fn v2_swap_eth_for_exact_tokens_real_calldata_decodes() {
    assert_decodes(
        "V2.swapETHForExactTokens",
        SwapETHForExactTokensDecoder::new(),
        V2_ROUTER,
        V2_SWAP_ETH_FOR_EXACT_TOKENS,
    );
}

#[test]
fn v3_exact_input_real_calldata_decodes() {
    assert_decodes(
        "V3.exactInput",
        ExactInputDecoder::new(),
        V3_ROUTER,
        V3_EXACT_INPUT,
    );
}

#[test]
fn v3_exact_output_real_calldata_decodes() {
    assert_decodes(
        "V3.exactOutput",
        ExactOutputDecoder::new(),
        V3_ROUTER,
        V3_EXACT_OUTPUT,
    );
}
